/**
 * Logs validation errors with detailed information about the error path
 * Uses console.error in development/local environments and console.warn in production
 *
 * The trace request ID is resolved with the following priority:
 * 1. From @meli/server-context (if installed in the consuming app)
 * 2. From the traceRequestId parameter (req.traceRequestId)
 * 3. 'N/A' if none available
 *
 * @param errors - Array of Zod validation errors
 * @param traceRequestId - Optional trace request ID from req.traceRequestId
 */
export declare const logValidationError: (errors: Array<any>, traceRequestId?: string) => void;
